class Solution(object):
    def minGroups(self, intervals):
        events = []
        for left, right in intervals:
            events.append((left, 1))
            events.append((right + 1, -1))
        events.sort()
        max_groups = 0
        current = 0
        for _, delta in events:
            current += delta
            max_groups = max(max_groups, current)
        return max_groups
